mapper.insert:
INSERT INTO WORKSPACE_INVITATION ( INVITATION_ID
                                 , WS_ID
                                 , INVITE_EMAIL
                                 , INVITE_TOKEN
                                 , AUTHORITY
                                 , STATUS
                                 , EXPIRE_DT
                                 , REGIST_DT
                                 , REGIST_ID)
VALUES ( #{invitationId,  jdbcType=VARCHAR}
       , #{wsId,          jdbcType=VARCHAR}
       , #{inviteEmail,   jdbcType=VARCHAR}
       , #{inviteToken,   jdbcType=VARCHAR}
       , #{authority,     jdbcType=VARCHAR}
       , #{status,        jdbcType=VARCHAR}
       , #{expireDt,      jdbcType=TIMESTAMP}
       , NOW()
       , #{registId,      jdbcType=VARCHAR})

mapper.update:
UPDATE WORKSPACE_INVITATION
SET STATUS = #{status, jdbcType=VARCHAR}
WHERE INVITATION_ID = #{invitationId, jdbcType=VARCHAR}

UPDATE WORKSPACE_INVITATION
SET STATUS           = 'ACCEPTED'
  , ACCEPTED_USER_ID = #{userId,       jdbcType=VARCHAR}
  , ACCEPTED_DT      = NOW()
WHERE INVITATION_ID  = #{invitationId, jdbcType=VARCHAR}

mapper.select:
SELECT COUNT(1) > 0
FROM WORKSPACE_USER
WHERE WS_ID   = #{wsId,   jdbcType=VARCHAR}
  AND USER_ID = #{userId, jdbcType=VARCHAR}
